def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.zeros_like(bins, dtype=float)
    for i, cap in enumerate(bins):
        base_penalty = 0.0
        base_score = 0.0
        complexity_factor = 1.0
        interaction_sum = 0.0
        adjustment_factor = 1.0
        if cap <= item:
            priorities[i] = np.inf
            continue
        for m in range(1, 8):
            if m % 2 == 0:
                base_score += (np.tanh(item / (cap + m)) + m**1.5) * (0.8 + 0.05*m)
            else:
                base_score += (np.cos(item * m / (cap + 1)) + m**0.9) * (0.9 - 0.03*m)
            if (cap + m*item) % 4 == 0:
                base_penalty += np.log1p(abs(cap - item*m)) / (m + 1)
            else:
                base_penalty -= np.sqrt(abs(cap - item/(m+1))) / (m + 2)
            if (cap * m) % 3 == 0:
                complexity_factor *= 1.02 + 0.01*m
            else:
                complexity_factor *= 0.97 - 0.005*m
            for n in range(1, m+1):
                val = (item * n) / (cap + m + n)
                if val < 0.5:
                    interaction_sum += np.sin(val * np.pi) * (m - n + 1) * 0.1
                else:
                    interaction_sum -= np.log1p(val * n) * 0.07
            if m == 5:
                temp_adj = 1.0
                for p in range(1, 4):
                    diff = cap - item*p*m
                    if diff > 0 and diff % (p+2) == 0:
                        temp_adj *= 1 + 0.03 * p
                    else:
                        temp_adj *= 0.95 - 0.02 * p
                adjustment_factor *= temp_adj
        combined_score = (base_score - base_penalty + interaction_sum) * complexity_factor * adjustment_factor
        if combined_score < 0:
            priorities[i] = np.abs(combined_score) / (cap + 1) * (1 + (item/cap)**2)
        else:
            priorities[i] = -combined_score / (np.sqrt(cap) + 2) * np.exp(-item/cap)
        if item / cap > 0.9:
            priorities[i] *= 1.2
        elif item / cap < 0.1:
            priorities[i] *= 0.7
        if cap % 3 == 0:
            priorities[i] *= 0.95
        else:
            priorities[i] *= 1.05
        if abs(cap - item) < 1e-3:
            priorities[i] *= 1.1 + 0.05 * np.sin(cap)
    return priorities
